// ============================================
// LEARNING WORKFLOW - OPTIMIZED CODE NODE v2.0
// ============================================
// IMPROVEMENTS:
// - Configurable parameters (no magic numbers)
// - Empty data guard
// - Reduced AI payload (Top 10 + Bottom 5 only)
// - Pattern counts without full text
// - Hook template extraction
// ============================================

// ============================================
// CONFIGURATION - Easy to adjust
// ============================================
const CONFIG = {
  analysisDays: 7,
  minTweetsForAnalysis: 5,

  // AI payload reduction - only send these
  topPerformersToSend: 10,
  bottomPerformersToSend: 5,

  // Performance tier thresholds
  percentileThresholds: {
    viral: 90,
    strong: 70,
    average: 40,
    weak: 20
  },

  // Composite score weights (must sum to 1.0)
  compositeWeights: {
    views: 0.30,
    engagement: 0.35,
    bookmarks: 0.25,
    velocity: 0.10
  },

  // Fatigue detection
  fatigueThresholds: {
    overuseCount: 3,  // Pattern used more than 3x = overused
    declinePercent: 20  // >20% decline = fatigued
  }
};

// Get all input data from previous nodes
const tweets = $('Get Latest Tweets').all();
const previousLearnings = $('Get Latest Learnings').all();
const weeklyAnalysis = $('Get Weekly Analysis').all();

// ============================================
// EMPTY DATA GUARD
// ============================================
if (tweets.length < CONFIG.minTweetsForAnalysis) {
  return [{
    json: {
      error: 'Insufficient data',
      message: `Only ${tweets.length} tweets found. Minimum required: ${CONFIG.minTweetsForAnalysis}`,
      analysisDate: new Date().toISOString(),
      metrics: {
        totalPosts: tweets.length,
        status: 'skipped'
      },
      status: 'skipped'
    }
  }];
}

// ============================================
// HELPER FUNCTIONS
// ============================================

function percentile(arr, val) {
  if (arr.length === 0) return 50;
  const sorted = [...arr].sort((a, b) => a - b);
  const idx = sorted.findIndex(v => v >= val);
  if (idx === -1) return 100;
  return Math.round((idx / arr.length) * 100);
}

function extractDayOfWeek(dateStr) {
  if (!dateStr) return 'Unknown';
  const date = new Date(dateStr);
  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  return days[date.getDay()] || 'Unknown';
}

function extractTimeSlot(dateStr) {
  if (!dateStr) return 'Unknown';
  const date = new Date(dateStr);
  const hour = date.getHours();
  if (hour < 7) return 'early_morning';
  if (hour < 9) return '7am';
  if (hour < 12) return '9am';
  if (hour < 14) return '12pm';
  if (hour < 16) return '2pm';
  if (hour < 19) return '4pm';
  if (hour < 22) return '7pm';
  return '11pm';
}

function detectSyntaMention(text) {
  if (!text) return { mentioned: false, position: null };
  const lowerText = text.toLowerCase();
  const syntaKeywords = ['synta', 'mcp', 'n8n', 'workflow', 'automation'];

  for (const keyword of syntaKeywords) {
    const idx = lowerText.indexOf(keyword);
    if (idx !== -1) {
      const position = idx < text.length * 0.3 ? 'hook' : 
                       idx < text.length * 0.7 ? 'middle' : 'end';
      return { mentioned: true, position, keyword };
    }
  }
  return { mentioned: false, position: null };
}

function detectCTAType(text) {
  if (!text) return 'none';
  const lower = text.toLowerCase();

  if (/comment|drop a|type|reply with|tell me/i.test(lower)) return 'comment_trigger';
  if (/follow for|must be following|follow me/i.test(lower)) return 'follow_trigger';
  if (/link|check out|grab|get it/i.test(lower)) return 'link_drop';
  if (/retweet|rt|share/i.test(lower)) return 'retweet_ask';
  if (/bookmark|save this/i.test(lower)) return 'bookmark_ask';
  if (/\?$/.test(text.trim())) return 'soft_ask'; // Ends with question

  return 'none';
}

function calculateVelocity(views, hoursLive) {
  if (!hoursLive || hoursLive === 0) return 0;
  // Views per hour, normalized to 0-100 scale
  const viewsPerHour = views / hoursLive;
  return Math.min(100, Math.round(viewsPerHour / 100)); // 10K views/hour = 100
}

// ============================================
// EXTRACT METRIC ARRAYS FOR PERCENTILE CALC
// ============================================
const allViews = tweets.map(t => t.json['View Count'] || t.json.viewCount || 0);
const allEngagements = tweets.map(t => t.json['Total Engagement'] || t.json.totalEngagement || 0);
const allBookmarks = tweets.map(t => t.json['Bookmark Count'] || t.json.bookmarkCount || 0);

// ============================================
// PROCESS EACH TWEET - COMPREHENSIVE METRICS
// ============================================
const processedTweets = tweets.map(tweet => {
  const data = tweet.json;

  // Extract raw metrics
  const views = data['View Count'] || data.viewCount || 1;
  const likes = data['Like Count'] || data.likeCount || 0;
  const retweets = data['Retweet Count'] || data.retweetCount || 0;
  const replies = data['Reply Count'] || data.replyCount || 0;
  const quotes = data['Quote Count'] || data.quoteCount || 0;
  const bookmarks = data['Bookmark Count'] || data.bookmarkCount || 0;
  const totalEngagement = data['Total Engagement'] || data.totalEngagement || (likes + retweets + replies + quotes);
  const createdAt = data['Created At'] || data.createdAt;

  // Calculate rates
  const engagementRate = (totalEngagement / views) * 100;
  const bookmarkRate = (bookmarks / views) * 100;
  const replyRate = (replies / views) * 100;

  // Calculate hours live (for velocity)
  let hoursLive = 24; // Default
  if (createdAt) {
    const postDate = new Date(createdAt);
    const now = new Date();
    hoursLive = Math.max(1, (now - postDate) / (1000 * 60 * 60));
  }

  // Calculate velocity
  const velocity = calculateVelocity(views, hoursLive);

  // Calculate percentiles
  const viewsPercentile = percentile(allViews, views);
  const engagementPercentile = percentile(allEngagements, totalEngagement);
  const bookmarkPercentile = percentile(allBookmarks, bookmarks);

  // COMPOSITE SCORE FORMULA - Using CONFIG weights
  const compositeScore = Math.min(100, Math.round(
    (viewsPercentile * CONFIG.compositeWeights.views) +
    (engagementPercentile * CONFIG.compositeWeights.engagement) +
    (bookmarkPercentile * CONFIG.compositeWeights.bookmarks) +
    (velocity * CONFIG.compositeWeights.velocity)
  ));

  // Assign Performance Tier - Using CONFIG thresholds
  let tier;
  if (compositeScore >= CONFIG.percentileThresholds.viral) tier = 'viral';
  else if (compositeScore >= CONFIG.percentileThresholds.strong) tier = 'strong';
  else if (compositeScore >= CONFIG.percentileThresholds.average) tier = 'average';
  else if (compositeScore >= CONFIG.percentileThresholds.weak) tier = 'weak';
  else tier = 'flop';

  // Extract full text for analysis
  const fullText = data.Text || data.text || '';
  const hook = data.Hook || data.hook || fullText.split('\n')[0] || '';

  // Detect patterns (deterministic)
  const syntaInfo = detectSyntaMention(fullText);
  const ctaType = detectCTAType(fullText);
  const dayOfWeek = extractDayOfWeek(createdAt);
  const timeSlot = extractTimeSlot(createdAt);

  return {
    // Identifiers
    id: data.id,
    tweetId: data['Tweet ID'] || data.tweetId,

    // FULL CONTENT (for AI to analyze)
    hook: hook,
    text: fullText,

    // Metadata
    author: data.Author || data.author || 'justben_builds',
    url: data.URL || data.url,
    contentType: data['Content Type'] || data.contentType || '',
    createdAt: createdAt,
    collectedAt: data['Collected At'] || data.collectedAt,
    daysSincePosted: data['Days Since Posted'] || data.daysSincePosted || 0,

    // TIME ANALYSIS (NEW)
    dayOfWeek: dayOfWeek,
    timeSlot: timeSlot,
    hoursLive: Math.round(hoursLive),

    // RAW METRICS
    likeCount: likes,
    retweetCount: retweets,
    replyCount: replies,
    quoteCount: quotes,
    bookmarkCount: bookmarks,
    viewCount: views,
    totalEngagement: totalEngagement,

    // CALCULATED RATES
    engagementRate: parseFloat(engagementRate.toFixed(2)),
    bookmarkRate: parseFloat(bookmarkRate.toFixed(3)),
    replyRate: parseFloat(replyRate.toFixed(3)),
    velocity: velocity,

    // PERCENTILES
    viewsPercentile: viewsPercentile,
    engagementPercentile: engagementPercentile,
    bookmarkPercentile: bookmarkPercentile,

    // FINAL SCORE
    compositeScore: compositeScore,
    performanceTier: tier,

    // PATTERN DETECTION (Deterministic)
    syntaMention: syntaInfo,
    ctaType: ctaType,

    // Flags from original data
    isViralPattern: data['Is Viral Pattern'] || data.isViralPattern || false,
    isThread: data['Is Thread'] || data.isThread || false,
    hasMedia: !!(data['Media URLs'] || data.mediaUrls),
    textLength: fullText.length,
    wordCount: fullText.split(/\s+/).filter(w => w).length,
    content_format: data.content_format || data['content_format'] || null,
    postCount: data.post_count || data['post_count'] || 1
  };
});

// Sort by composite score
const sortedTweets = [...processedTweets].sort((a, b) => b.compositeScore - a.compositeScore);

// Add ranking
sortedTweets.forEach((tweet, idx) => {
  tweet.rank = idx + 1;
  tweet.percentileRank = Math.round(((sortedTweets.length - idx) / sortedTweets.length) * 100);
});

// ============================================
// PRE-AGGREGATE STATISTICS
// ============================================
const totalTweets = sortedTweets.length;

// Basic aggregates
const avgCompositeScore = totalTweets > 0 
  ? parseFloat((sortedTweets.reduce((sum, t) => sum + t.compositeScore, 0) / totalTweets).toFixed(1))
  : 0;
const avgEngagementRate = totalTweets > 0 
  ? parseFloat((sortedTweets.reduce((sum, t) => sum + t.engagementRate, 0) / totalTweets).toFixed(2))
  : 0;
const avgBookmarkRate = totalTweets > 0 
  ? parseFloat((sortedTweets.reduce((sum, t) => sum + t.bookmarkRate, 0) / totalTweets).toFixed(3))
  : 0;
const avgVelocity = totalTweets > 0
  ? parseFloat((sortedTweets.reduce((sum, t) => sum + t.velocity, 0) / totalTweets).toFixed(1))
  : 0;
const avgViews = totalTweets > 0
  ? Math.round(sortedTweets.reduce((sum, t) => sum + t.viewCount, 0) / totalTweets)
  : 0;

// Tier distribution
const tierDistribution = {
  viral: sortedTweets.filter(t => t.performanceTier === 'viral').length,
  strong: sortedTweets.filter(t => t.performanceTier === 'strong').length,
  average: sortedTweets.filter(t => t.performanceTier === 'average').length,
  weak: sortedTweets.filter(t => t.performanceTier === 'weak').length,
  flop: sortedTweets.filter(t => t.performanceTier === 'flop').length
};

// ============================================
// TIME ANALYSIS AGGREGATES (NEW)
// ============================================
const dayStats = {};
const timeSlotStats = {};

sortedTweets.forEach(t => {
  // Day aggregation
  if (!dayStats[t.dayOfWeek]) {
    dayStats[t.dayOfWeek] = { posts: 0, totalScore: 0, totalBookmarkRate: 0 };
  }
  dayStats[t.dayOfWeek].posts++;
  dayStats[t.dayOfWeek].totalScore += t.compositeScore;
  dayStats[t.dayOfWeek].totalBookmarkRate += t.bookmarkRate;

  // Time slot aggregation
  if (!timeSlotStats[t.timeSlot]) {
    timeSlotStats[t.timeSlot] = { posts: 0, totalScore: 0 };
  }
  timeSlotStats[t.timeSlot].posts++;
  timeSlotStats[t.timeSlot].totalScore += t.compositeScore;
});

// Calculate averages
const timeAnalysis = {
  byDay: {},
  byTimeSlot: {}
};

for (const day in dayStats) {
  timeAnalysis.byDay[day] = {
    posts: dayStats[day].posts,
    avgScore: parseFloat((dayStats[day].totalScore / dayStats[day].posts).toFixed(1)),
    avgBookmarkRate: parseFloat((dayStats[day].totalBookmarkRate / dayStats[day].posts).toFixed(3))
  };
}

for (const slot in timeSlotStats) {
  timeAnalysis.byTimeSlot[slot] = {
    posts: timeSlotStats[slot].posts,
    avgScore: parseFloat((timeSlotStats[slot].totalScore / timeSlotStats[slot].posts).toFixed(1))
  };
}

// ============================================
// CTA ANALYSIS AGGREGATES (NEW)
// ============================================
const ctaStats = {};
sortedTweets.forEach(t => {
  if (!ctaStats[t.ctaType]) {
    ctaStats[t.ctaType] = { posts: 0, totalScore: 0, totalReplies: 0, totalBookmarkRate: 0 };
  }
  ctaStats[t.ctaType].posts++;
  ctaStats[t.ctaType].totalScore += t.compositeScore;
  ctaStats[t.ctaType].totalReplies += t.replyCount;
  ctaStats[t.ctaType].totalBookmarkRate += t.bookmarkRate;
});

const ctaAnalysis = {};
for (const cta in ctaStats) {
  ctaAnalysis[cta] = {
    posts: ctaStats[cta].posts,
    avgScore: parseFloat((ctaStats[cta].totalScore / ctaStats[cta].posts).toFixed(1)),
    avgReplies: parseFloat((ctaStats[cta].totalReplies / ctaStats[cta].posts).toFixed(1)),
    avgBookmarkRate: parseFloat((ctaStats[cta].totalBookmarkRate / ctaStats[cta].posts).toFixed(3))
  };
}

// ============================================
// SYNTA/PRODUCT MENTION ANALYSIS (NEW)
// ============================================
const withSynta = sortedTweets.filter(t => t.syntaMention.mentioned);
const withoutSynta = sortedTweets.filter(t => !t.syntaMention.mentioned);

const syntaAnalysis = {
  totalMentions: withSynta.length,
  avgScoreWithSynta: withSynta.length > 0 
    ? parseFloat((withSynta.reduce((sum, t) => sum + t.compositeScore, 0) / withSynta.length).toFixed(1))
    : 0,
  avgScoreWithoutSynta: withoutSynta.length > 0
    ? parseFloat((withoutSynta.reduce((sum, t) => sum + t.compositeScore, 0) / withoutSynta.length).toFixed(1))
    : 0,
  avgBookmarkRateWithSynta: withSynta.length > 0
    ? parseFloat((withSynta.reduce((sum, t) => sum + t.bookmarkRate, 0) / withSynta.length).toFixed(3))
    : 0,
  byPosition: {
    hook: withSynta.filter(t => t.syntaMention.position === 'hook').length,
    middle: withSynta.filter(t => t.syntaMention.position === 'middle').length,
    end: withSynta.filter(t => t.syntaMention.position === 'end').length
  }
};

// ============================================
// BOOKMARK-SPECIFIC ANALYSIS (NEW)
// ============================================
const sortedByBookmarks = [...sortedTweets].sort((a, b) => b.bookmarkRate - a.bookmarkRate);
const topBookmarkPosts = sortedByBookmarks.slice(0, 5).map(t => ({
  tweetId: t.tweetId,
  hook: t.hook.substring(0, 100),
  bookmarkRate: t.bookmarkRate,
  compositeScore: t.compositeScore,
  ctaType: t.ctaType
}));

const bookmarkAnalysis = {
  avgBookmarkRate: avgBookmarkRate,
  topBookmarkPosts: topBookmarkPosts,
  highBookmarkThreshold: sortedByBookmarks.length > 0 ? sortedByBookmarks[Math.floor(sortedByBookmarks.length * 0.2)]?.bookmarkRate || 0 : 0,
  lowBookmarkThreshold: sortedByBookmarks.length > 0 ? sortedByBookmarks[Math.floor(sortedByBookmarks.length * 0.8)]?.bookmarkRate || 0 : 0
};

// ============================================
// FORMAT ANALYSIS (NEW)
// ============================================
const formatStats = {
  single_tweet: { posts: 0, totalScore: 0 },
  thread: { posts: 0, totalScore: 0 },
  short: { posts: 0, totalScore: 0 },
  medium: { posts: 0, totalScore: 0 },
  long: { posts: 0, totalScore: 0 }
};

sortedTweets.forEach(t => {
  // Thread vs single
  if (t.isThread) {
    formatStats.thread.posts++;
    formatStats.thread.totalScore += t.compositeScore;
  } else {
    formatStats.single_tweet.posts++;
    formatStats.single_tweet.totalScore += t.compositeScore;
  }

  // Length categorization
  if (t.wordCount < 30) {
    formatStats.short.posts++;
    formatStats.short.totalScore += t.compositeScore;
  } else if (t.wordCount < 80) {
    formatStats.medium.posts++;
    formatStats.medium.totalScore += t.compositeScore;
  } else {
    formatStats.long.posts++;
    formatStats.long.totalScore += t.compositeScore;
  }
});

const formatAnalysis = {};
for (const format in formatStats) {
  if (formatStats[format].posts > 0) {
    formatAnalysis[format] = {
      posts: formatStats[format].posts,
      avgScore: parseFloat((formatStats[format].totalScore / formatStats[format].posts).toFixed(1))
    };
  }
}

// ============================================
// GRANULAR FORMAT PERFORMANCE (content_format field)
// ============================================
const formatDetailStats = {};
sortedTweets.forEach(t => {
  // Use content_format if available, fallback to heuristic detection
  const fmt = t.content_format || (t.isThread ? 'thread_2' : t.wordCount < 30 ? 'short_punchy' : t.wordCount < 80 ? 'medium_story' : 'long_insight');
  if (!formatDetailStats[fmt]) {
    formatDetailStats[fmt] = { posts: 0, totalScore: 0, totalViews: 0, totalBookmarkRate: 0 };
  }
  formatDetailStats[fmt].posts++;
  formatDetailStats[fmt].totalScore += t.compositeScore;
  formatDetailStats[fmt].totalViews += t.viewCount;
  formatDetailStats[fmt].totalBookmarkRate += t.bookmarkRate;
});

const formatPerformance = {};
for (const [fmt, stats] of Object.entries(formatDetailStats)) {
  formatPerformance[fmt] = {
    posts: stats.posts,
    avgScore: parseFloat((stats.totalScore / stats.posts).toFixed(1)),
    avgViews: Math.round(stats.totalViews / stats.posts),
    avgBookmarkRate: parseFloat((stats.totalBookmarkRate / stats.posts).toFixed(3))
  };
}

// ============================================
// EXTRACT PREVIOUS CONTEXT
// ============================================
const previousLearningContext = previousLearnings.length > 0
  ? previousLearnings.map(l => {
      const data = l.json;
      return {
        ...data,
        // Extract structured fields for hypothesis resolution
        _previousHypotheses: (() => {
          try { return JSON.parse(data.newHypotheses || '[]'); } catch(e) { return []; }
        })(),
        _previousCooldowns: (() => {
          try { return JSON.parse(data.cooldowns || '[]'); } catch(e) { return []; }
        })(),
        _previousContentPlan: (() => {
          try { return JSON.parse(data.weeklyContentPlan || '{}'); } catch(e) { return {}; }
        })()
      };
    })
  : [];

const weeklyAnalysisContext = weeklyAnalysis.length > 0
  ? {
      latestAnalysis: weeklyAnalysis[0].json,
      totalAnalysesAvailable: weeklyAnalysis.length,
      // Adapted WF4 fields (new schema)
      stealAngles: weeklyAnalysis[0].json.steal_angles || weeklyAnalysis[0].json['Steal Angles'] || null,
      hookFormulasExternal: weeklyAnalysis[0].json.hook_formulas || weeklyAnalysis[0].json['Hook Analysis'] || null,
      contentGaps: weeklyAnalysis[0].json.content_gaps || weeklyAnalysis[0].json['Content Gaps'] || null,
      fatigueAlertsExternal: weeklyAnalysis[0].json.fatigue_alerts || weeklyAnalysis[0].json['Fatigue Signals'] || weeklyAnalysis[0].json.fatigueSignals || null,
      trendingFormats: weeklyAnalysis[0].json.trending_formats || null,
      marketAmmoBrief: weeklyAnalysis[0].json.market_ammo_brief || null,
      // Legacy fields (backward compatibility)
      previousRecommendations: weeklyAnalysis[0].json['Strategic Recommendations'] || weeklyAnalysis[0].json.recommendations || null,
      previousViralPatterns: weeklyAnalysis[0].json['Top Viral Patterns'] || weeklyAnalysis[0].json.winningHooks || null,
      previousHookAnalysis: weeklyAnalysis[0].json['Hook Analysis'] || null,
      previousVoicePatterns: weeklyAnalysis[0].json['Voice Patterns'] || null,
      previousFatigueSignals: weeklyAnalysis[0].json['Fatigue Signals'] || weeklyAnalysis[0].json.fatigueSignals || null,
      previousDiversityScore: weeklyAnalysis[0].json.diversityScore || null,
      previousAvgScore: weeklyAnalysis[0].json.metrics?.avgCompositeScore || null,
      previousCooldowns: weeklyAnalysis[0].json.cooldowns || null,
      previousHypotheses: weeklyAnalysis[0].json.hypotheses || null
    }
  : null;

// Calculate week-over-week changes if we have previous data
let weekOverWeekChange = null;
// Try previousLearnings first (our own past data), then weeklyAnalysis
const prevLearningScore = previousLearningContext.length > 0
  ? previousLearningContext[0].avgCompositeScore || null
  : null;
const prevScore = prevLearningScore || weeklyAnalysisContext?.previousAvgScore || null;
if (prevScore) {
  const change = ((avgCompositeScore - prevScore) / prevScore) * 100;
  weekOverWeekChange = {
    compositeScore: (change >= 0 ? '+' : '') + change.toFixed(1) + '%',
    raw: change,
    source: prevLearningScore ? 'learningPatterns' : 'weeklyAnalysis'
  };
}

// ============================================
// HOOK TYPE DETECTION (for pattern counting)
// ============================================
function detectHookType(text) {
  if (!text) return 'unknown';
  const lower = text.toLowerCase();
  const firstLine = text.split('\n')[0] || text;

  if (/i just|i found|just built|just discovered/i.test(lower)) return 'discovery';
  if (/\$[\d,]+|\d+%|\d+x|\d+ (hours|days|minutes)/i.test(firstLine)) return 'shock_stat';
  if (/unpopular opinion|hot take|controversial|nobody.*wants/i.test(lower)) return 'controversy';
  if (/\?\s*$/.test(firstLine)) return 'question';
  if (/^(I |My |When I )/i.test(firstLine)) return 'personal_story';
  if (/\d+\s*(tips|ways|steps|things|reasons)/i.test(lower)) return 'list';
  if (/nobody knows|secret|most people|what .* don't/i.test(lower)) return 'curiosity_gap';
  if (/how to|step[- ]by[- ]step|tutorial|guide/i.test(lower)) return 'tutorial';
  if (/breaking|just announced|news:|update:/i.test(lower)) return 'news_commentary';

  return 'standard';
}

// ============================================
// TOPIC DETECTION (for pattern counting)
// ============================================
function detectTopic(text) {
  if (!text) return 'general';
  const lower = text.toLowerCase();

  if (/consultant|agency|agencies|\$\d+k|charging|overpriced/i.test(lower)) return 'anti_consultant';
  if (/n8n/i.test(lower)) return 'n8n_specific';
  if (/mcp|server|claude/i.test(lower)) return 'mcp_features';
  if (/gpt|chatgpt|openai|gemini|llm|ai tool/i.test(lower)) return 'ai_tools';
  if (/built|building|here's how|step \d/i.test(lower)) return 'build_tutorial';
  if (/real estate|legal|healthcare|finance|industry/i.test(lower)) return 'industry_specific';
  if (/automation|automate|workflow/i.test(lower)) return 'automation_general';
  if (/^(I |My |When I |Last week)/i.test(text)) return 'personal_insight';

  return 'general';
}

// ============================================
// TONE DETECTION
// ============================================
function detectTone(text) {
  if (!text) return 'neutral';
  const lower = text.toLowerCase();

  if (/scam|fraud|exposed|attack|calling out|stop|wrong/i.test(lower)) return 'aggressive';
  if (/learn|tip|how to|guide|here's|tutorial/i.test(lower)) return 'educational';
  if (/hot take|unpopular|controversial|debate/i.test(lower)) return 'controversial';
  if (/honest|struggle|failed|mistake|learned/i.test(lower)) return 'vulnerable';
  if (/lol|lmao|😂|funny|joke/i.test(lower)) return 'humorous';

  return 'neutral';
}

// Add classifications to all tweets
sortedTweets.forEach(t => {
  t.hookType = detectHookType(t.text);
  t.topic = detectTopic(t.text);
  t.tone = detectTone(t.text);
});

// ============================================
// PATTERN COUNTS (aggregated, no full text)
// ============================================
function countByProperty(arr, prop) {
  return arr.reduce((acc, item) => {
    const key = item[prop] || 'unknown';
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
}

const patternCounts = {
  byHookType: countByProperty(sortedTweets, 'hookType'),
  byTopic: countByProperty(sortedTweets, 'topic'),
  byTone: countByProperty(sortedTweets, 'tone'),
  byCtaType: countByProperty(sortedTweets, 'ctaType'),
  byTier: tierDistribution
};

// Flag overused patterns
const overusedPatterns = [];
for (const [pattern, count] of Object.entries(patternCounts.byHookType)) {
  if (count > CONFIG.fatigueThresholds.overuseCount) {
    overusedPatterns.push({ type: 'hookType', pattern, count, threshold: CONFIG.fatigueThresholds.overuseCount });
  }
}
for (const [pattern, count] of Object.entries(patternCounts.byTopic)) {
  if (count > CONFIG.fatigueThresholds.overuseCount) {
    overusedPatterns.push({ type: 'topic', pattern, count, threshold: CONFIG.fatigueThresholds.overuseCount });
  }
}

// ============================================
// TOP & WORST PERFORMERS (EXPANDED for AI)
// ============================================
const topPerformers = sortedTweets.slice(0, CONFIG.topPerformersToSend).map(t => ({
  tweetId: t.tweetId,
  hook: t.hook,
  text: t.text,  // Full text for top performers
  compositeScore: t.compositeScore,
  performanceTier: t.performanceTier,
  views: t.viewCount,
  engagementRate: t.engagementRate,
  bookmarkRate: t.bookmarkRate,
  velocity: t.velocity,
  ctaType: t.ctaType,
  hookType: t.hookType,
  topic: t.topic,
  tone: t.tone,
  dayOfWeek: t.dayOfWeek,
  timeSlot: t.timeSlot,
  syntaMention: t.syntaMention,
  textLength: t.textLength,
  wordCount: t.wordCount
}));

const worstPerformers = sortedTweets.slice(-CONFIG.bottomPerformersToSend).reverse().map(t => ({
  tweetId: t.tweetId,
  hook: t.hook,
  text: t.text,  // Full text for worst performers too
  compositeScore: t.compositeScore,
  performanceTier: t.performanceTier,
  views: t.viewCount,
  engagementRate: t.engagementRate,
  bookmarkRate: t.bookmarkRate,
  ctaType: t.ctaType,
  hookType: t.hookType,
  topic: t.topic,
  tone: t.tone,
  dayOfWeek: t.dayOfWeek,
  timeSlot: t.timeSlot
}));

// ============================================
// OUTPUT FOR AI AGENT
// ============================================
return [{
  json: {
    // Metadata
    analysisDate: new Date().toISOString(),
    analysisId: `LEARN_${Date.now()}`,
    periodStart: sortedTweets.length > 0 
      ? sortedTweets.reduce((min, t) => t.createdAt < min ? t.createdAt : min, sortedTweets[0].createdAt)
      : null,
    periodEnd: sortedTweets.length > 0 
      ? sortedTweets.reduce((max, t) => t.createdAt > max ? t.createdAt : max, sortedTweets[0].createdAt)
      : null,

    // ENHANCED SUMMARY METRICS
    metrics: {
      totalPosts: totalTweets,
      avgViews: avgViews,
      avgEngagementRate: avgEngagementRate,
      avgBookmarkRate: avgBookmarkRate,
      avgVelocity: avgVelocity,
      avgCompositeScore: avgCompositeScore,
      topScore: sortedTweets.length > 0 ? sortedTweets[0].compositeScore : 0,
      bottomScore: sortedTweets.length > 0 ? sortedTweets[sortedTweets.length - 1].compositeScore : 0,
      tierDistribution: tierDistribution,
      weekOverWeekChange: weekOverWeekChange
    },

    // PRE-AGGREGATED ANALYSIS (Deterministic)
    timeAnalysis: timeAnalysis,
    ctaAnalysis: ctaAnalysis,
    syntaAnalysis: syntaAnalysis,
    bookmarkAnalysis: bookmarkAnalysis,
    formatAnalysis: formatAnalysis,
    formatPerformance: formatPerformance,

    // TOP/WORST PERFORMERS (for AI deep analysis)
    topPerformers: topPerformers,
    worstPerformers: worstPerformers,

    // PATTERN COUNTS (replaces full tweets array - 60% token reduction)
    patternCounts: patternCounts,
    overusedPatterns: overusedPatterns,

    // MIDDLE PERFORMERS (summary only, no full text)
    middlePerformersSummary: sortedTweets
      .slice(CONFIG.topPerformersToSend, -CONFIG.bottomPerformersToSend)
      .map(t => ({
        tweetId: t.tweetId,
        hookPreview: t.hook.substring(0, 80),
        compositeScore: t.compositeScore,
        hookType: t.hookType,
        topic: t.topic,
        tone: t.tone,
        ctaType: t.ctaType
      })),

    // CONFIG used (for transparency)
    configUsed: CONFIG,

    // HISTORICAL CONTEXT
    previousLearnings: previousLearningContext,
    weeklyAnalysisContext: weeklyAnalysisContext,

    // Validation counts
    inputCounts: {
      tweetsReceived: tweets.length,
      previousLearningsReceived: previousLearnings.length,
      weeklyAnalysisReceived: weeklyAnalysis.length
    }
  }
}];

// ============================================
// FORMAT AI OUTPUT - Sanitizer & Validator v1.0
// ============================================
// Placed between AI Agent and Airtable writes.
// Ensures all fields are properly typed/defaulted
// so the "Create a record" node never gets
// undefined, wrong types, or malformed JSON.
// ============================================

const rawInput = $input.first().json;

// ============================================
// STEP 1: Find the actual AI output
// The Structured Output Parser can nest output
// at different depths depending on success/failure
// ============================================
let parsed = null;
let rawForDebug = '';

function isValidOutput(obj) {
  return obj && typeof obj === 'object' && !Array.isArray(obj) && (
    obj.weekStart !== undefined ||
    obj.summary !== undefined ||
    obj.winningHooks !== undefined ||
    obj.metrics !== undefined
  );
}

function tryParseString(val) {
  if (typeof val !== 'string') return null;
  // Direct parse
  try { const o = JSON.parse(val); if (isValidOutput(o)) return o; } catch(e) {}
  // Extract from markdown code block
  const cbMatch = val.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (cbMatch) {
    try { const o = JSON.parse(cbMatch[1].trim()); if (isValidOutput(o)) return o; } catch(e) {}
  }
  // Extract first { to last }
  const start = val.indexOf('{');
  const end = val.lastIndexOf('}');
  if (start !== -1 && end > start) {
    try { const o = JSON.parse(val.substring(start, end + 1)); if (isValidOutput(o)) return o; } catch(e) {}
  }
  return null;
}

// Save raw for debugging
try { rawForDebug = JSON.stringify(rawInput).substring(0, 50000); } catch(e) { rawForDebug = String(rawInput).substring(0, 50000); }

// Try paths where the output might live
if (isValidOutput(rawInput.output)) {
  parsed = rawInput.output;
} else if (rawInput.output && isValidOutput(rawInput.output.output)) {
  parsed = rawInput.output.output;
} else if (isValidOutput(rawInput)) {
  parsed = rawInput;
} else {
  // Try parsing string values
  parsed = tryParseString(rawInput.output)
    || tryParseString(rawInput.output?.output)
    || tryParseString(rawInput.text)
    || tryParseString(rawInput.response)
    || {};
}

const parserFailed = !parsed || Object.keys(parsed).length === 0;

// ============================================
// STEP 2: Type-safe helper functions
// ============================================

function safeString(val, fallback) {
  if (val === null || val === undefined) return fallback !== undefined ? fallback : '';
  if (typeof val === 'string') return val;
  if (typeof val === 'object') {
    try { return JSON.stringify(val); } catch(e) { return fallback || ''; }
  }
  return String(val);
}

function safeNumber(val, fallback) {
  if (val === null || val === undefined) return fallback !== undefined ? fallback : 0;
  const num = Number(val);
  return isNaN(num) ? (fallback !== undefined ? fallback : 0) : num;
}

function safeArray(val) {
  if (Array.isArray(val)) return val;
  if (typeof val === 'string') {
    try {
      const arr = JSON.parse(val);
      if (Array.isArray(arr)) return arr;
    } catch(e) {}
    return val.trim() ? [val] : [];
  }
  if (val && typeof val === 'object') return [val];
  return [];
}

function safeObject(val) {
  if (val && typeof val === 'object' && !Array.isArray(val)) return val;
  if (typeof val === 'string') {
    try {
      const obj = JSON.parse(val);
      if (obj && typeof obj === 'object' && !Array.isArray(obj)) return obj;
    } catch(e) {}
  }
  return {};
}

function truncate(str, max) {
  max = max || 95000;
  if (!str || typeof str !== 'string') return str || '';
  return str.length <= max ? str : str.substring(0, max) + '\n...[TRUNCATED]';
}

// ============================================
// STEP 3: Extract & validate metrics sub-object
// The Create a record node reaches into
// $json.output.metrics?.totalPosts etc.
// ============================================
const rawMetrics = safeObject(parsed.metrics);

const metrics = {
  totalPosts: safeNumber(rawMetrics.totalPosts),
  avgEngagementRate: safeNumber(rawMetrics.avgEngagementRate),
  avgCompositeScore: safeNumber(rawMetrics.avgCompositeScore),
  avgBookmarkRate: safeNumber(rawMetrics.avgBookmarkRate),
  topScore: safeNumber(rawMetrics.topScore),
  bottomScore: safeNumber(rawMetrics.bottomScore),
  weekOverWeekChange: typeof rawMetrics.weekOverWeekChange === 'object'
    ? safeString(rawMetrics.weekOverWeekChange.compositeScore, 'N/A')
    : safeString(rawMetrics.weekOverWeekChange, 'N/A')
};

// ============================================
// STEP 4: Build validated output
// Preserves $json.output.* shape so the
// existing Airtable node expressions work
// with ZERO changes to the Airtable mapping
// ============================================

const validated = {
  // Dates - fall back to sensible defaults
  weekStart: safeString(parsed.weekStart) || new Date(Date.now() - 7 * 86400000).toISOString().split('T')[0],
  weekEnd: safeString(parsed.weekEnd) || new Date().toISOString().split('T')[0],

  // Identity
  account_id: safeString(parsed.account_id, 'jb'),

  // Summary
  summary: truncate(safeString(parsed.summary, parserFailed ? 'AI output parsing failed - see analysisRaw for raw response' : 'Analysis completed')),

  // Metrics sub-object (for $json.output.metrics?.X expressions)
  metrics: metrics,

  // Numeric fields
  diversityScore: safeNumber(parsed.diversityScore),

  // String fields - with empty-string fallback
  accountVoiceProfile: truncate(safeString(parsed.accountVoiceProfile, '')),
  audienceSignals: truncate(safeString(parsed.audienceSignals, '')),
  externalContextUsed: truncate(safeString(parsed.externalContextUsed, '')),
  analysisRaw: truncate(parserFailed ? ('PARSER_FAILED. Raw input:\n' + rawForDebug) : safeString(parsed.analysisRaw, '')),

  // Array fields - guaranteed arrays so JSON.stringify() works
  winningHooks: safeArray(parsed.winningHooks),
  winningStructures: safeArray(parsed.winningStructures),
  winningTones: safeArray(parsed.winningTones),
  topicPerformance: safeArray(parsed.topicPerformance),
  fatigueSignals: safeArray(parsed.fatigueSignals),
  emergingOpportunities: safeArray(parsed.emergingOpportunities),
  antiSlopAlerts: safeArray(parsed.antiSlopAlerts),
  exploit: safeArray(parsed.exploit),
  explore: safeArray(parsed.explore),
  reduce: safeArray(parsed.reduce),
  kill: safeArray(parsed.kill),
  cooldowns: safeArray(parsed.cooldowns),
  hypothesisResults: safeArray(parsed.hypothesisResults),
  newHypotheses: safeArray(parsed.newHypotheses),
  topPerformers: safeArray(parsed.topPerformers),
  worstPerformers: safeArray(parsed.worstPerformers),

  // Object fields - guaranteed objects so JSON.stringify() works
  timeSlotInsights: safeObject(parsed.timeSlotInsights),
  weeklyContentPlan: safeObject(parsed.weeklyContentPlan),

  // Status always Current for new records
  status: 'Current'
};

// ============================================
// OUTPUT: { output: validated } so downstream
// Airtable expressions like
//   $json.output.weekStart
//   $json.output.metrics?.totalPosts
//   JSON.stringify($json.output.winningHooks || [])
// all work without any changes
// ============================================
return [{
  json: {
    output: validated,
    _format_meta: {
      version: '1.0',
      parsed_ok: !parserFailed,
      fields_found: Object.keys(parsed || {}).length,
      timestamp: new Date().toISOString()
    }
  }
}];
